import anthropic
import json

client = anthropic.Anthropic()

# Tool definition that forces explicit fact verification
verify_fact_tool = {
    "name": "verify_fact",
    "description": (
        "Look up a fact in a trusted knowledge base to confirm it. "
        "Call this before asserting any specific claim, date, number, or name."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "claim": {
                "type": "string",
                "description": "The specific factual claim to verify.",
            },
            "expected_value": {
                "type": "string",
                "description": "What you believe the answer to be.",
            },
        },
        "required": ["claim"],
    },
}

def tool_grounded_generation(prompt: str) -> tuple[str, list[dict]]:
    """
    Use tool-calling to force explicit verification of claims.
    Returns (final_text, list_of_verified_claims).
    """
    messages = [{"role": "user", "content": prompt}]
    verified_claims = []

    # Agentic loop: run until no more tool calls
    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=600,
            tools=[verify_fact_tool],
            messages=messages,
        )

        # Collect any text content
        final_text = ""
        tool_calls = []
        for block in response.content:
            if block.type == "text":
                final_text = block.text
            elif block.type == "tool_use":
                tool_calls.append(block)

        if not tool_calls or response.stop_reason == "end_turn":
            break

        # Simulate tool results and track verified claims
        tool_results = []
        for call in tool_calls:
            claim = call.input.get("claim", "")
            verified_claims.append(claim)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": call.id,
                "content": f"Verified: claim recorded for '{claim}'",
            })

        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})

    return final_text, verified_claims


text, claims = tool_grounded_generation(
    "Share three facts about the Python programming language, "
    "using the verify_fact tool for each claim before stating it."
)
print("Output:", text[:200])
print("Verified claims:", claims)
